var e=[{id:`L6_1`,type:`dialog`,speaker:`REBECCA_DELTA_NULL_NULL`,text:{KOREA:`미안하지만 나한테 그런 시시한 총알은 안 박힌다고!`,JPN:`悪いけど、オレに弾丸なんてものは効かねえ！`,ENG:`Sorry, but those bullets won't work on me!`,TWN:`不好意思，用那些子彈可打不中我！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:null,C:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`닥쳐! 당장 그만두라고! 대체 이게 무슨 짓이야!`,JPN:`黙って！　今すぐやめなさい！　何の真似ですか！`,ENG:`Shut up! Stop what you're doing right now! What's the meaning of this?!`,TWN:`閉嘴！馬上給我停下來！你到底在幹什麼！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`REBECCA_DELTA_NULL_NULL`,text:{KOREA:`오호, 소령과 다르게 이쪽은 제법 공격이 날카로운데? 받아 칠 맛이 나겠어.`,JPN:`へえ、少佐と違って、こっちの攻撃は結構鋭いな？　打ち返し甲斐がある。`,ENG:`Oh? Your attacks are quite threatening, unlike Major's. This is gonna be fun.`,TWN:`哇喔，這邊的攻擊和少校不同，很有二下子喔？讓我提起戰鬥興致了。`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`카린 양! 이쪽은 제가 맡을 테니까 어서 가세요! 빨리요!`,JPN:`カリンさん！　こちらは任せて行ってください！　早く！`,ENG:`Karin! Leave this to me! You go ahead! Hurry!`,TWN:`卡琳！這邊交給我，去做你的事！快點！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`뒤는 맡기겠습니다!`,JPN:`後は頼みます！`,ENG:`Thank you!`,TWN:`後面就拜託你了！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`REBECCA_DELTA_NULL_NULL`,text:{KOREA:`뭐라는 거야! 누가 순순히 보내줄 것……`,JPN:`何言ってんだよ！　誰が行かせるって……`,ENG:`What?! I'm not gonna just let you–`,TWN:`說什麼呢！別想就這麼跑……`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:null,C:null,R:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`REBECCA_DELTA_NULL_NULL`,text:{KOREA:`읏!`,JPN:`うっ！`,ENG:`Ngh!`,TWN:`唔！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L20_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`글쎄? 순순히 보내줄 수밖에 없을 걸?`,JPN:`どうかな？　行かせる以外に手はないと思うよ？`,ENG:`Oh really? I think you are just gonna let her go that easily.`,TWN:`是嗎？你還是乖乖地在這裡看著吧？`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REBECCA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`오랜만에 꽤 진심으로 해볼 생각이 들었거든.`,JPN:`久しぶりに本気出しちゃおうかと思っているからね。`,ENG:`I haven't fought seriously in a long time, but I'm excited now.`,TWN:`真是好久沒有那麼認真了。`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`박사님! 포인트를 재확보하였습니다!`,JPN:`博士！　ポイントを再確保しました！`,ENG:`Doctor! I've re-secured my position!`,TWN:`博士！我重新回到了狙擊點！`},stage:{bg:`CITY_TWILIGHT`,slots:{L:null,C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`차원 통로는! 차원 통로는 어떻게 되었죠!?`,JPN:`次元通路は！　次元通路はどうなっていますか！？`,ENG:`The dimensional passage! What happened to it?!`,TWN:`次元通道呢！次元通道怎麼樣了？！`},stage:{bg:`CITY_TWILIGHT`,slots:{L:null,C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`LONE_EXILER_NPC_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CITY_TWILIGHT`,slots:{L:{char_id:`LONE_EXILER_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`LONE_EXILER_NPC_NULL`,text:{KOREA:`늦었어. 차원통로는 소멸했어. 작전은 실패야.`,JPN:`もう遅い。次元通路は消滅した。作戦失敗だ。`,ENG:`It's too late. The dimensional passage is gone. This operation is a failure.`,TWN:`太晚了，次元通道已經消失了，作戰失敗了。`},stage:{bg:`CITY_TWILIGHT`,slots:{L:{char_id:`LONE_EXILER_NPC_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`이, 이럴 수가……!`,JPN:`そ、そんな……！`,ENG:`I-it can't be...!`,TWN:`怎，怎麼會……！`},stage:{bg:`CITY_TWILIGHT`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`또야, 또 나 때문이야……!`,JPN:`まただ、また私のせいで……！`,ENG:`Again... It's my fault again...!`,TWN:`又，又是因為我……！`},stage:{bg:`CITY_TWILIGHT`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};